#include<iostream>#include<vector>#include<algorithm>#include<cmath>#define ll long longusing namespace std;int main(){    int t;    cin>>t;    while(t--){        ll n;        cin>>n;        vector<ll> a(n);        for(int i=0;i<n;i++){            cin>>a[i];        }        vector<ll>prefix(n,0);        prefix[0]=a[0];        for(int i=1;i<n;i++){            prefix[i]=prefix[i-1]+a[i];        }        ll ans=0;        for(int k=1;k<=n;k++){            if(n%k) continue;            ll start= k-1;                        ll maxi= prefix[start];            ll mini= prefix[start];            for(int i=start + k;i<n;i+=k){               ll curr= prefix[i]-prefix[i-k];                maxi= max(maxi,curr);                mini= min(mini,curr);            }            ans= max(ans,maxi-mini);        }        cout<<ans<<"\n";    }}